import type { SupplierContract } from '../types';import { SupplierStatusBadge } from './SupplierStatusBadge';
export const ContractTimeline=({contracts,onEdit,onDelete}:{contracts:SupplierContract[];onEdit?:(c:SupplierContract)=>void;onDelete?:(c:SupplierContract)=>void})=>{if(!contracts.length)return <p className="rounded-xl border border-dashed p-8 text-center text-sm text-slate-500 dark:border-slate-700">No contracts recorded.</p>;return <ol className="relative space-y-5 border-l border-slate-200 pl-6 dark:border-slate-700">{contracts.map(c=><li key={c.id} className="relative rounded-xl border border-slate-200 bg-white p-4 dark:border-slate-700 dark:bg-slate-900"><span className="absolute -left-[1.92rem] top-5 h-3 w-3 rounded-full bg-indigo-600 ring-4 ring-white dark:ring-slate-950"/><div className="flex flex-wrap items-start justify-between gap-2"><div><p className="font-mono text-sm font-bold text-slate-900 dark:text-white">{c.contract_number}</p><p className="mt-1 text-xs text-slate-500">{c.start_date} → {c.end_date}</p></div><SupplierStatusBadge status={(c.is_expiring===true||c.is_expiring===1)?'expiring':c.status}/></div><div className="mt-3 flex flex-wrap gap-4 text-sm"><span>{c.currency} {Number(c.contract_value).toLocaleString()}</span><span className={c.days_remaining<=30?'font-semibold text-amber-600':'text-slate-500'}>{c.days_remaining} days remaining</span>{c.renewal_date?<span className="text-slate-500">Renewal: {c.renewal_date}</span>:null}</div>{c.attachment_reference?<a href={c.attachment_reference} target="_blank" rel="noreferrer" className="mt-3 inline-block text-xs font-semibold text-indigo-600">Attachment placeholder: {c.attachment_name||'reference'}</a>:null}{onEdit?<button type="button" onClick={()=>onEdit(c)} className="mt-3 text-xs font-semibold text-indigo-600">Edit contract</button>:null}{onDelete?<button type="button" onClick={()=>onDelete(c)} className="ml-4 mt-3 text-xs font-semibold text-red-600">Terminate</button>:null}</li>)}</ol>;};
